// Generated by GitHub Copilot
import { useState, useEffect, useCallback } from 'react'
import { FiShield, FiFilter, FiRefreshCw } from 'react-icons/fi'
import PageHeader from '../../components/ui/PageHeader.jsx'
import Card, { CardBody } from '../../components/ui/Card.jsx'
import Select from '../../components/ui/Select.jsx'
import Button from '../../components/ui/Button.jsx'
import Badge from '../../components/ui/Badge.jsx'
import Table, { THead, TBody, TR, TH, TD } from '../../components/ui/Table.jsx'
import EmptyState from '../../components/ui/EmptyState.jsx'
import { auditApi } from '../../api/auditApi.js'
import { formatDate } from '../../utils/format.js'

const ACTION_OPTIONS = [
  { value: '', label: 'All actions' },
  { value: 'LOGIN', label: 'Login' },
  { value: 'MEMBER_CREATED', label: 'Member created' },
  { value: 'MEMBER_UPDATED', label: 'Member updated' },
  { value: 'MEMBER_DELETED', label: 'Member deleted' },
  { value: 'MEMBER_STATUS_CHANGED', label: 'Member status changed' },
  { value: 'CONTRIBUTION_RECORDED', label: 'Contribution recorded' },
  { value: 'CONTRIBUTION_STATUS_CHANGED', label: 'Contribution status changed' },
  { value: 'LOAN_ISSUED', label: 'Loan issued' },
  { value: 'LOAN_STATUS_CHANGED', label: 'Loan status changed' },
  { value: 'REPAYMENT_RECORDED', label: 'Repayment recorded' },
  { value: 'SETTINGS_UPDATED', label: 'Settings updated' },
]

const ENTITY_OPTIONS = [
  { value: '', label: 'All entities' },
  { value: 'Auth', label: 'Auth' },
  { value: 'Member', label: 'Member' },
  { value: 'Contribution', label: 'Contribution' },
  { value: 'Loan', label: 'Loan' },
  { value: 'LoanRepayment', label: 'Loan Repayment' },
  { value: 'ContributionSetting', label: 'Settings' },
]

const ROLE_OPTIONS = [
  { value: '', label: 'All roles' },
  { value: 'admin', label: 'Admin' },
  { value: 'member', label: 'Member' },
]

/**
 * Maps an audit action to a Badge variant for visual distinction.
 * @param {string} action
 * @returns {string} Badge variant
 */
function actionVariant(action) {
  if (action === 'LOGIN') return 'info'
  if (action.includes('DELETED') || action === 'LOAN_STATUS_CHANGED') return 'danger'
  if (action.includes('CREATED') || action.includes('ISSUED') || action.includes('RECORDED')) return 'success'
  return 'warning'
}

/** Admin-only audit log explorer with filters and pagination. */
export default function AuditLogs() {
  const [logs, setLogs] = useState([])
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  const [filters, setFilters] = useState({
    action: '',
    entity: '',
    performedByRole: '',
    startDate: '',
    endDate: '',
  })
  const [page, setPage] = useState(1)

  const fetchLogs = useCallback(async () => {
    setLoading(true)
    setError('')
    try {
      const result = await auditApi.getLogs({ ...filters, page, limit: 20 })
      setLogs(result.logs || [])
      setPagination({ page: result.page, pages: result.pages, total: result.total })
    } catch (err) {
      setError(err.message || 'Failed to load audit logs')
    } finally {
      setLoading(false)
    }
  }, [filters, page])

  useEffect(() => {
    fetchLogs()
  }, [fetchLogs])

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }))
    setPage(1)
  }

  const handleReset = () => {
    setFilters({ action: '', entity: '', performedByRole: '', startDate: '', endDate: '' })
    setPage(1)
  }

  return (
    <div className="space-y-6">
      <PageHeader
        title="Audit Logs"
        subtitle="Complete history of all system actions"
        icon={<FiShield className="h-6 w-6 text-brand-600" />}
      />

      {/* Filters */}
      <Card>
        <CardBody>
          <div className="flex flex-wrap items-end gap-3">
            <div className="flex items-center gap-1 text-sm font-medium text-slate-600">
              <FiFilter className="h-4 w-4" />
              Filters
            </div>

            <Select
              value={filters.action}
              onChange={(e) => handleFilterChange('action', e.target.value)}
              aria-label="Filter by action"
              className="w-48"
            >
              {ACTION_OPTIONS.map((o) => (
                <option key={o.value} value={o.value}>{o.label}</option>
              ))}
            </Select>

            <Select
              value={filters.entity}
              onChange={(e) => handleFilterChange('entity', e.target.value)}
              aria-label="Filter by entity"
              className="w-40"
            >
              {ENTITY_OPTIONS.map((o) => (
                <option key={o.value} value={o.value}>{o.label}</option>
              ))}
            </Select>

            <Select
              value={filters.performedByRole}
              onChange={(e) => handleFilterChange('performedByRole', e.target.value)}
              aria-label="Filter by role"
              className="w-32"
            >
              {ROLE_OPTIONS.map((o) => (
                <option key={o.value} value={o.value}>{o.label}</option>
              ))}
            </Select>

            <div className="flex flex-col gap-1">
              <label htmlFor="startDate" className="text-xs text-slate-500">From</label>
              <input
                id="startDate"
                type="date"
                value={filters.startDate}
                onChange={(e) => handleFilterChange('startDate', e.target.value)}
                className="rounded-lg border border-slate-200 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand-500"
                aria-label="Start date"
              />
            </div>

            <div className="flex flex-col gap-1">
              <label htmlFor="endDate" className="text-xs text-slate-500">To</label>
              <input
                id="endDate"
                type="date"
                value={filters.endDate}
                onChange={(e) => handleFilterChange('endDate', e.target.value)}
                className="rounded-lg border border-slate-200 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand-500"
                aria-label="End date"
              />
            </div>

            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={handleReset}>
                Reset
              </Button>
              <Button variant="outline" size="sm" onClick={fetchLogs} aria-label="Refresh logs">
                <FiRefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
              </Button>
            </div>
          </div>
        </CardBody>
      </Card>

      {/* Table */}
      <Card>
        <CardBody className="p-0">
          {error ? (
            <div className="p-6 text-sm text-red-600" role="alert">{error}</div>
          ) : (
            <Table>
              <THead>
                <TR>
                  <TH>Timestamp</TH>
                  <TH>Action</TH>
                  <TH>Entity</TH>
                  <TH>Description</TH>
                  <TH>Performed by</TH>
                  <TH>IP Address</TH>
                </TR>
              </THead>
              <TBody>
                {loading ? (
                  Array.from({ length: 5 }).map((_, i) => (
                    <TR key={i}>
                      {Array.from({ length: 6 }).map((__, j) => (
                        <TD key={j}>
                          <div className="h-4 w-full animate-pulse rounded bg-slate-200" />
                        </TD>
                      ))}
                    </TR>
                  ))
                ) : logs.length === 0 ? (
                  <TR>
                    <TD colSpan={6}>
                      <EmptyState title="No audit logs found" message="Try adjusting the filters." />
                    </TD>
                  </TR>
                ) : (
                  logs.map((log) => (
                    <TR key={log._id}>
                      <TD className="whitespace-nowrap text-xs text-slate-500">
                        {formatDate(log.createdAt)}
                      </TD>
                      <TD>
                        <Badge variant={actionVariant(log.action)} size="sm">
                          {log.action.replace(/_/g, ' ')}
                        </Badge>
                      </TD>
                      <TD className="text-sm text-slate-600">{log.entity}</TD>
                      <TD className="max-w-xs truncate text-sm text-slate-700" title={log.description}>
                        {log.description || '—'}
                      </TD>
                      <TD className="text-sm">
                        {log.performedByName ? (
                          <span>
                            <span className="font-medium text-slate-700">{log.performedByName}</span>
                            <span className="ml-1 text-xs capitalize text-slate-400">({log.performedByRole})</span>
                          </span>
                        ) : (
                          <span className="text-slate-400">—</span>
                        )}
                      </TD>
                      <TD className="font-mono text-xs text-slate-500">
                        {log.ipAddress || '—'}
                      </TD>
                    </TR>
                  ))
                )}
              </TBody>
            </Table>
          )}
        </CardBody>
      </Card>

      {/* Pagination */}
      {!loading && pagination.pages > 1 && (
        <div className="flex items-center justify-between text-sm text-slate-600">
          <span>{pagination.total} total logs</span>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              disabled={page <= 1}
              onClick={() => setPage((p) => p - 1)}
              aria-label="Previous page"
            >
              Previous
            </Button>
            <span>
              Page {pagination.page} of {pagination.pages}
            </span>
            <Button
              variant="outline"
              size="sm"
              disabled={page >= pagination.pages}
              onClick={() => setPage((p) => p + 1)}
              aria-label="Next page"
            >
              Next
            </Button>
          </div>
        </div>
      )}
    </div>
  )
}
